import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { ItemsList } from '@ng-select/ng-select/lib/items-list';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { AddSystemService } from 'src/app/shared/services/add-system.service';
import { RoleService } from 'src/app/shared/services/role.service';
import { RuleService } from 'src/app/shared/services/rule.service';
import Swal from 'sweetalert2';

@Component({
  selector: 'npr-rule-mapping',
  templateUrl: './rule-mapping.component.html',
  styleUrls: ['./rule-mapping.component.scss'],
})
export class RuleMappingComponent implements OnInit {
  dtTrigger: any = new Subject();
  dtOptions: DataTables.Settings = {};
  ruleMappingListResp: any = [];
  isLoading: boolean = false;
  roleCodes = new permissionsLabels();
  currentUser: string;
  addSysRespData: Object;
  editBtn: boolean;
  authBtn: boolean;
  deleted: boolean;
  reopenBtn: boolean;
  authorizeDone: boolean;
  closeBtn: boolean;
  authBtnHide: boolean;
  statusArr: String[] = ['Authorized', 'Unauthorized', 'Open', 'Close'];

  constructor(
    private rulelist: RuleService,
    private roleService: RoleService,
    private router: Router,
    private addSystem: AddSystemService,
    private cdr: ChangeDetectorRef
  ) {}

  ngOnInit(): void {
    this.currentUser = localStorage.getItem('userFromLogin');
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength: 5,
      columnDefs: [{ type: 'date', targets: [4] }],
      order: [[4, 'desc']],
      processing: true,
      lengthMenu: [
        [5, 10, 20, 30,-1],
        [5, 10, 20, 30,"ALL"],
      ],
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],
    };

    this.fetchinglistRuleMapping();
    this.roleService.fetchScreenPermissions('Rule Mapping');
    this.roleService.screenLabelList.subscribe(
      (message) => (this.roleCodes = message)
    );
    console.log(this.roleCodes);
  }

  fetchinglistRuleMapping() {
    this.isLoading = true;
    this.rulelist.fetchingruleMapping().subscribe((resp: any) => {
      for (let item of resp.result) {
        item.recordStatus = this.statusArr.find((i) =>
          i.startsWith(item.recordStatus)
        );
        item.approvedStatus = this.statusArr.find((i)=>
        i.startsWith(item.approvedStatus)
        );
      }
      console.log(resp);
      this.ruleMappingListResp = resp.result;
      this.isLoading = false;
      this.cdr.markForCheck();

      this.dtTrigger.next();
    });
  }

  getById(data) {
    console.log('OnClick', data);
    let id: any = 0;
    if (data.msgMappingDetails.length > 0) {
      id = data.msgMappingDetails[0].messageMappingId;
    }

    this.rulelist.getruleMappingById(id, data.mappingId).subscribe((resp) => {
      console.log(resp);
      let queryParams = {
        sourceTransDetId: resp.sourceTransDetId,
        targetTransDetId: resp.targetTransDetId,
        mdmtMessageMappingDet: resp.mdmtMessageMappingDet,
        responseData: data,
      };
      console.log(queryParams);
      this.addSystem.sendNavParam(queryParams);
      this.router.navigate(['/rule-mapping/edit', data.mappingId]);
    });
  }
  open(data){
    console.log(data);
    Swal.fire(
      {
        //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
        text: 'You are trying to re-open record. ' + ' Do you want to proceed?',
        showCancelButton: true,
        confirmButtonColor: '#3e54b8',
        cancelButtonColor: '#d33',
        // confirmButtonText: 'PROCEED.'
        cancelButtonText: 'NO',
        confirmButtonText: 'YES', 'icon': 'info', iconColor: "#d33"
      }
    ).then((result => {
      console.log("this is reopen ", result);
      if (result.isConfirmed === true) {
        
        this.rulelist.editRuleMapping("open", this.currentUser, data).subscribe((resp) => {
          this.addSysRespData = resp;
          this.authBtnHide = false;
          this.editBtn = false;
          this.authBtn = false;
          Swal.fire({ text: 'Record is Opened', icon: 'success' }).then(() => window.location.reload());
          // this.toastService.successMessage('Record Opened!', '');
        });
      }
    }))

  }
  close(data){
    console.log(data);
    Swal.fire(
      {
        //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
        text: 'You are trying to close record. ' + ' Do you want to proceed?',
        showCancelButton: true,
        confirmButtonColor: '#3e54b8',
        cancelButtonColor: '#d33',
        // confirmButtonText: 'PROCEED.'
        cancelButtonText: 'NO',
        confirmButtonText: 'YES', 'icon': 'info', iconColor: "#d33"
      }
    ).then((result => {
      console.log("this is reopen ", result);
      if (result.isConfirmed === true) {
        // let payloadObj: any = {};
        // payloadObj = this.ruleMappingDataForPayload;
        // payloadObj.msgMappingDetails = this.rulemappingDetail;
        this.rulelist.editRuleMapping("close", this.currentUser, data).subscribe((resp) => {
          this.addSysRespData = resp;
          this.editBtn = true;
          this.authBtn = true;
          this.deleted = false;
          this.reopenBtn = false;
          Swal.fire({ text: 'Record is  Closed', icon: 'success' }).then(() => window.location.reload());
          // this.toastService.successMessage('Record is Closed', '');
        });
      }
    }))
  


  }
  delete(data){
    console.log(data);
    
    Swal.fire(
      {
        //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
        text: 'You are trying to delete record. ' + ' Do you want to proceed?',
        showCancelButton: true,
        confirmButtonColor: '#3e54b8',
        cancelButtonColor: '#d33',
        // confirmButtonText: 'PROCEED.'
        cancelButtonText: 'NO',
        confirmButtonText: 'YES', 'icon': 'info', iconColor: "#d33"
      }
    ).then((result => {
      console.log("this is reopen ", result);
      if (result.isConfirmed === true) {
        this.rulelist.ondeleteMapping(data.mappingId, this.currentUser).subscribe((resp) => {
          if (resp) {
            this.deleted = true;
            this.editBtn = true;
            this.authBtn = true;
            this.closeBtn = true;

            // this.toastService.successMessage('Deleted Successfully!', '');

            Swal.fire({
              title: 'Record is Deleted',
              confirmButtonText: 'Ok'
            }).then(() => window.location.reload());

          }
          else {
            Swal.fire("Failed to delete the reocrd");
          }
        });
      }
    }))

  }
  auth(data){
    console.log(data);
    Swal.fire(
      {
        //text: 'Unable to process' + 'Error ' + this.responseforfileupload.errorMessage + 'Do you want to Proceed??',
        text: 'You are trying to Authorize record. ' + ' Do you want to proceed?',
        showCancelButton: true,
        confirmButtonColor: '#3085d6',
        cancelButtonColor: '#d33',
        // confirmButtonText: 'PROCEED.'
        cancelButtonText: 'NO',
        confirmButtonText: 'YES', 'icon': 'info'
      }
    ).then((result => {
      console.log("this is reopen ", result);
      if (result.isConfirmed === true) {
        console.log(data.creatorId);
        

        if (this.currentUser == data.creatorId) {
          Swal.fire('Maker cannot authorize the record!');
          // this.toastService.successMessage('Maker cannot authorize!', '');
        }
        else {
          
          this.rulelist.editRuleMapping("auth", this.currentUser, data).subscribe((resp) => {
            this.authorizeDone = true;
            this.addSysRespData = resp;
            Swal.fire({ text: 'Record is Authorized' }).then(() => window.location.reload());
            // this.toastService.successMessage('Record Authorized!', '');
          });
        }
      }
    }))

  }

  ngOnDestroy(): void {
    // Do not forget to unsubscribe the event
    this.dtTrigger.unsubscribe();
  }
}
